        let left = column 0
        let counts = column 1 |&gt; Seq.countBy id |&gt; Map.ofSeq

        let getCount id =
            Map.tryFind id counts |&gt; Option.defaultValue 0

        left |&gt; Seq.sumBy (fun id -&gt; getCount id * id)
